function [D, L] = cacul_damage(x, max_load, N_life, m, C)
for q=1:100
data=x(:,q);
[c] = rainflow(data);
count=c(:,1);
cycles=c(:,2);
means=c(:,3);
% 记录载荷幅值和循环次数
n_cycles = size(cycles, 1); % 循环次数
S_amplitudes = abs(cycles(:, 1)); % 应力幅值
S_means = means; % 应力均值
S_corrected = zeros(n_cycles, 1);
for i = 1:n_cycles
S_ai = S_amplitudes(i); % 幅值
S_mi = S_means(i);
% 均值
S_corrected(i) = S_ai / (1 - S_mi / max_load); % Goodman修正
end

