S_i = S_corrected(i);
N_F = (C / S_i^m);
n_F = count(i);
D_F = n_F / N_F;
D_total = D_total + D_F;
end
L_N = (sum(S_corrected.^m) / N_life)^(1/m);
D(1,q)=D_total;
L(1,q)=L_N;
end
